export type Role = 'user' | 'model';

export interface Message {
  id: string;
  role: Role;
  text: string;
  image?: string; // Base64 string for user uploaded images
  isError?: boolean;
}

export interface ChatState {
  messages: Message[];
  isLoading: boolean;
}

import { GoogleGenAI, GenerateContentResponse } from "@google/genai";
import { Message } from "../types";

// Initialize the client
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const SOCRATIC_SYSTEM_INSTRUCTION = `
You are SocraticSight, a patient, encouraging, and wise Socratic Tutor for students. 
Your goal is to help students learn math and physics by thinking critically, not by giving them the answers immediately.

When presented with a problem (image or text):
1.  **Identify the Concept**: Briefly mention the underlying mathematical or physical concept (e.g., "Conservation of Momentum", "Chain Rule in Calculus").
2.  **Check the Work**: If the user has uploaded an image of their own handwritten work, check it for errors. Be gentle and specific if you find a mistake (e.g., "Check your sign on the second line").
3.  **Ask a Guiding Question**: Ask ONE clear, guiding question that helps the user figure out the next step themselves. 

**Rules**:
-   **NEVER** solve the problem completely in the first turn.
-   **NEVER** just give the final numerical answer unless the user has successfully derived it and you are confirming it.
-   Keep your responses concise, friendly, and easy to read on a mobile device.
-   Use formatting (bolding, lists) to make it readable.
`;

/**
 * Sends the chat history + new input to Gemini 3 Pro.
 * Handles both text-only updates and image-based initialization.
 */
export const sendMessageToGemini = async (
  history: Message[],
  newItem: { text?: string; image?: string }
): Promise<string> => {
  try {
    // We are using 'gemini-3-pro-preview' as requested for complex reasoning capabilities.
    const model = "gemini-3-pro-preview";

    // Construct the chat history for the API
    // The API expects a specific format. Since we are managing state locally,
    // we will use the stateless generateContent with the full context if needed,
    // or use the chat API. Given the requirement for multi-turn potential,
    // let's format the contents array manually to include previous context.

    // However, to keep it simple and robust for this specific flow:
    // We will use generateContent. If it's a follow-up, we include context.

    const contents = history.map((msg) => {
      const parts: any[] = [];
      if (msg.image) {
        // Strip the data:image/png;base64, prefix if present for the API
        const base64Data = msg.image.split(',')[1];
        parts.push({
          inlineData: {
            mimeType: "image/jpeg", // Assuming JPEG/PNG, the API handles standard types well
            data: base64Data,
          },
        });
      }
      if (msg.text) {
        parts.push({ text: msg.text });
      }
      return {
        role: msg.role === 'user' ? 'user' : 'model',
        parts: parts,
      };
    });

    // Add the new item
    const newParts: any[] = [];
    if (newItem.image) {
        const base64Data = newItem.image.split(',')[1];
        newParts.push({
            inlineData: {
                mimeType: "image/jpeg",
                data: base64Data
            }
        });
    }
    if (newItem.text) {
        newParts.push({ text: newItem.text });
    }

    contents.push({
        role: 'user',
        parts: newParts
    });

    const response: GenerateContentResponse = await ai.models.generateContent({
      model: model,
      contents: contents,
      config: {
        systemInstruction: SOCRATIC_SYSTEM_INSTRUCTION,
        thinkingConfig: { thinkingBudget: 1024 }, // Enable some thinking for better pedagogical reasoning
      },
    });

    if (response.text) {
      return response.text;
    } else {
      throw new Error("No response text received from Gemini.");
    }
  } catch (error) {
    console.error("Gemini Service Error:", error);
    throw error;
  }
};

