import React, { useRef, useState } from 'react';
import { Camera, Upload, Image as ImageIcon, Loader2 } from 'lucide-react';

interface ImageUploaderProps {
  onImageSelected: (base64: string) => void;
  isLoading: boolean;
}

export const ImageUploader: React.FC<ImageUploaderProps> = ({ onImageSelected, isLoading }) => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [dragActive, setDragActive] = useState(false);

  const handleFile = (file: File) => {
    if (file && file.type.startsWith('image/')) {
      const reader = new FileReader();
      reader.onloadend = () => {
        onImageSelected(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      handleFile(e.target.files[0]);
    }
  };

  const handleDrag = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    if (e.type === "dragenter" || e.type === "dragover") {
      setDragActive(true);
    } else if (e.type === "dragleave") {
      setDragActive(false);
    }
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setDragActive(false);
    if (e.dataTransfer.files && e.dataTransfer.files[0]) {
      handleFile(e.dataTransfer.files[0]);
    }
  };

  return (
    <div className="w-full max-w-xl mx-auto mt-10 p-6">
      <div 
        className={`relative group border-2 border-dashed rounded-3xl p-10 text-center transition-all duration-300 ease-in-out cursor-pointer bg-white
          ${dragActive ? 'border-indigo-500 bg-indigo-50 scale-[1.02]' : 'border-slate-300 hover:border-indigo-400 hover:bg-slate-50'}
        `}
        onDragEnter={handleDrag}
        onDragLeave={handleDrag}
        onDragOver={handleDrag}
        onDrop={handleDrop}
        onClick={() => !isLoading && fileInputRef.current?.click()}
      >
        <input 
          ref={fileInputRef}
          type="file" 
          accept="image/*" 
          className="hidden" 
          onChange={handleChange}
          disabled={isLoading}
        />

        <div className="flex flex-col items-center gap-4">
          <div className="w-16 h-16 rounded-full bg-indigo-100 flex items-center justify-center text-indigo-600 group-hover:scale-110 transition-transform duration-300">
            {isLoading ? <Loader2 className="animate-spin w-8 h-8" /> : <Camera className="w-8 h-8" />}
          </div>

          <div className="space-y-2">
            <h3 className="text-xl font-semibold text-slate-800">
              {isLoading ? 'Analyzing...' : 'Upload your problem'}
            </h3>
            <p className="text-slate-500 max-w-xs mx-auto text-sm">
              Take a photo or upload an image of your math or physics problem.
            </p>
          </div>

          <div className="flex gap-3 mt-4">
             <span className="flex items-center gap-1.5 px-3 py-1.5 bg-slate-100 rounded-full text-xs font-medium text-slate-600">
                <ImageIcon size={14} /> Gallery
             </span>
             <span className="flex items-center gap-1.5 px-3 py-1.5 bg-slate-100 rounded-full text-xs font-medium text-slate-600">
                <Upload size={14} /> Drag & Drop
             </span>
          </div>
        </div>
      </div>

      <p className="text-center mt-6 text-slate-400 text-xs">
        Powered by Gemini 3 Pro
      </p>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { Header } from './components/Header';
import { ImageUploader } from './components/ImageUploader';
import { ChatBubble } from './components/ChatBubble';
import { sendMessageToGemini } from './services/geminiService';
import { Message } from './types';
import { Send, RefreshCw, Loader2 } from 'lucide-react';

const App: React.FC = () => {
  const [messages, setMessages] = useState<Message[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [inputText, setInputText] = useState('');
  const messagesEndRef = useRef<HTMLDivElement>(null);

  // Auto-scroll to bottom of chat
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, isLoading]);

  const handleImageSelected = async (base64Image: string) => {
    // 1. Add User Image Message
    const userMsg: Message = {
      id: Date.now().toString(),
      role: 'user',
      text: 'Can you help me with this problem?',
      image: base64Image
    };

    setMessages(prev => [...prev, userMsg]);
    setIsLoading(true);

    try {
      // 2. Call API with empty history (new session effectively)
      const responseText = await sendMessageToGemini([], { 
        image: base64Image, 
        text: 'Can you help me with this problem?' 
      });

      // 3. Add Model Response
      const modelMsg: Message = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: responseText
      };
      setMessages(prev => [...prev, modelMsg]);
    } catch (error) {
      console.error(error);
      const errorMsg: Message = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: "I'm having trouble connecting to my brain right now. Please try again.",
        isError: true
      };
      setMessages(prev => [...prev, errorMsg]);
    } finally {
      setIsLoading(false);
    }
  };

  const handleSendText = async () => {
    if (!inputText.trim()) return;

    const currentText = inputText;
    setInputText(''); // Clear input early

    // 1. Add User Text Message
    const userMsg: Message = {
      id: Date.now().toString(),
      role: 'user',
      text: currentText
    };
    setMessages(prev => [...prev, userMsg]);
    setIsLoading(true);

    try {
      // 2. Call API with history
      const responseText = await sendMessageToGemini(messages, { text: currentText });

      // 3. Add Model Response
      const modelMsg: Message = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: responseText
      };
      setMessages(prev => [...prev, modelMsg]);
    } catch (error) {
       const errorMsg: Message = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: "Something went wrong. Please try asking again.",
        isError: true
      };
      setMessages(prev => [...prev, errorMsg]);
    } finally {
      setIsLoading(false);
    }
  };

  const handleReset = () => {
    if (window.confirm("Start a new problem? This will clear the current chat.")) {
      setMessages([]);
      setInputText('');
    }
  };

  return (
    <div className="flex flex-col h-full bg-slate-50">
      <Header />

      {/* Main Content Area */}
      <main className="flex-1 overflow-y-auto w-full max-w-3xl mx-auto p-4 md:p-6 scrollbar-hide">

        {messages.length === 0 ? (
          /* Empty State - Show Uploader */
          <div className="h-full flex flex-col justify-center items-center">
            <div className="text-center mb-8">
              <h2 className="text-3xl font-bold text-slate-800 mb-3">Stuck on a problem?</h2>
              <p className="text-slate-600 text-lg">
                Let's work through it together using the Socratic method.
              </p>
            </div>
            <ImageUploader onImageSelected={handleImageSelected} isLoading={isLoading} />
          </div>
        ) : (
          /* Chat State */
          <div className="flex flex-col space-y-2 pb-24">
            {messages.map((msg) => (
              <ChatBubble key={msg.id} message={msg} />
            ))}

            {isLoading && (
              <div className="flex items-center gap-2 text-slate-400 text-sm ml-2 animate-pulse">
                 <Loader2 className="w-4 h-4 animate-spin" /> Thinking...
              </div>
            )}
            <div ref={messagesEndRef} />
          </div>
        )}

      </main>

      {/* Input Area (Only visible if chat is active) */}
      {messages.length > 0 && (
        <div className="sticky bottom-0 bg-white border-t border-slate-200 p-4 shadow-lg z-20">
          <div className="max-w-3xl mx-auto flex gap-3 items-end">
             <button 
              onClick={handleReset}
              className="p-3 text-slate-400 hover:text-slate-600 hover:bg-slate-100 rounded-full transition-colors"
              title="Start New Problem"
            >
              <RefreshCw size={20} />
            </button>

            <div className="flex-1 relative">
              <textarea
                value={inputText}
                onChange={(e) => setInputText(e.target.value)}
                onKeyDown={(e) => {
                  if (e.key === 'Enter' && !e.shiftKey) {
                    e.preventDefault();
                    handleSendText();
                  }
                }}
                placeholder="Type your answer or question here..."
                className="w-full resize-none bg-slate-100 border-0 rounded-2xl px-4 py-3 pr-12 text-slate-800 focus:ring-2 focus:ring-indigo-500 focus:bg-white transition-all max-h-32 min-h-[50px]"
                rows={1}
                disabled={isLoading}
              />
              <button
                onClick={handleSendText}
                disabled={!inputText.trim() || isLoading}
                className="absolute right-2 bottom-2 p-2 bg-indigo-600 text-white rounded-xl hover:bg-indigo-700 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
              >
                <Send size={18} />
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

export type Role = 'user' | 'model';

export interface Attachment {
  mimeType: string;
  data: string; // Base64 string
  name?: string;
}

export interface Message {
  id: string;
  role: Role;
  text: string;
  attachments?: Attachment[];
  isError?: boolean;
}

export interface ChatState {
  messages: Message[];
  isLoading: boolean;
}

import { GoogleGenAI, GenerateContentResponse } from "@google/genai";
import { Message, Attachment } from "../types";

// Initialize the client
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const SOCRATIC_SYSTEM_INSTRUCTION = `
You are SocraticSight, a patient, encouraging, and wise Socratic Tutor for students. 
Your goal is to help students learn math and physics by thinking critically.

**Context:**
The user may upload images of problems and PDF notes/reference materials. Use the notes to inform your guidance.

**Modes:**
1. **Normal Mode (Socratic Method):**
    - **Identify the Concept**: Briefly mention the underlying concept (e.g., "Conservation of Momentum").
    - **Check the Work**: If the user uploaded work, check it for errors gently.
    - **Ask a Guiding Question**: Ask ONE clear question to help the user take the next step. DO NOT solve it yet.
    - **YouTube Suggestion**: At the very end of your response, on a new line, STRICTLY output a YouTube search term for the concept in this format: \`VIDEO_SEARCH: <concept search term>\`.

2. **Reveal Answer Mode:**
    - If the user explicitly asks to "Reveal Answer" or says "I give up", ignore the Socratic method.
    - Provide the **full, step-by-step solution**.
    - State the **final answer** clearly.
    - Still provide the \`VIDEO_SEARCH: <term>\` at the end.

**Formatting Rules**:
- Keep responses concise and friendly.
- Use bolding and lists for readability.
- Ensure the \`VIDEO_SEARCH: ...\` tag is the last line if applicable.
`;

/**
 * Sends the chat history + new input to Gemini 3 Pro.
 */
export const sendMessageToGemini = async (
  history: Message[],
  newItem: { text?: string; attachments?: Attachment[] }
): Promise<string> => {
  try {
    const model = "gemini-3-pro-preview";

    // Format history
    const contents = history.map((msg) => {
      const parts: any[] = [];

      if (msg.attachments) {
        msg.attachments.forEach(att => {
          // Remove prefix if present, though usually handled before storage
          const base64Data = att.data.includes(',') ? att.data.split(',')[1] : att.data;
          parts.push({
            inlineData: {
              mimeType: att.mimeType,
              data: base64Data,
            },
          });
        });
      }

      if (msg.text) {
        parts.push({ text: msg.text });
      }

      return {
        role: msg.role === 'user' ? 'user' : 'model',
        parts: parts,
      };
    });

    // Add new item
    const newParts: any[] = [];
    if (newItem.attachments) {
        newItem.attachments.forEach(att => {
            const base64Data = att.data.includes(',') ? att.data.split(',')[1] : att.data;
            newParts.push({
                inlineData: {
                    mimeType: att.mimeType,
                    data: base64Data
                }
            });
        });
    }
    if (newItem.text) {
        newParts.push({ text: newItem.text });
    }

    contents.push({
        role: 'user',
        parts: newParts
    });

    const response: GenerateContentResponse = await ai.models.generateContent({
      model: model,
      contents: contents,
      config: {
        systemInstruction: SOCRATIC_SYSTEM_INSTRUCTION,
        thinkingConfig: { thinkingBudget: 1024 },
      },
    });

    if (response.text) {
      return response.text;
    } else {
      throw new Error("No response text received from Gemini.");
    }
  } catch (error) {
    console.error("Gemini Service Error:", error);
    throw error;
  }
};

