import React from 'react';
import { Message } from '../types';
import { Bot, User, AlertCircle, FileText, Youtube, ExternalLink } from 'lucide-react';

interface ChatBubbleProps {
  message: Message;
}

export const ChatBubble: React.FC<ChatBubbleProps> = ({ message }) => {
  const isUser = message.role === 'user';
  const isError = message.isError;

  // Parse YouTube search term
  const youtubeRegex = /VIDEO_SEARCH:\s*(.+)/;
  const match = message.text.match(youtubeRegex);
  const videoTerm = match ? match[1].trim() : null;

  // Clean text by removing the metadata tag
  const displayText = message.text.replace(youtubeRegex, '').trim();

  return (
    <div className={`flex w-full mb-8 ${isUser ? 'justify-end' : 'justify-start'}`}>
      <div className={`flex max-w-[90%] md:max-w-[80%] gap-4 ${isUser ? 'flex-row-reverse' : 'flex-row'}`}>

        {/* Avatar */}
        <div className={`flex-shrink-0 w-10 h-10 rounded-xl flex items-center justify-center shadow-lg mt-1 ${
          isUser 
            ? 'bg-indigo-600 text-white' 
            : isError 
              ? 'bg-red-900/50 text-red-400 border border-red-800' 
              : 'bg-emerald-600/20 text-emerald-400 border border-emerald-500/30'
        }`}>
          {isUser ? <User size={20} /> : isError ? <AlertCircle size={20} /> : <Bot size={20} />}
        </div>

        {/* Content Bubble */}
        <div className="flex flex-col gap-2 w-full">
          {/* Attachments Grid */}
          {message.attachments && message.attachments.length > 0 && (
            <div className={`grid gap-2 mb-1 ${message.attachments.length > 1 ? 'grid-cols-2' : 'grid-cols-1'}`}>
              {message.attachments.map((att, idx) => (
                <div key={idx} className="relative group rounded-lg overflow-hidden border border-slate-700 bg-slate-800">
                  {att.mimeType === 'application/pdf' ? (
                    <div className="flex items-center justify-center h-32 bg-slate-800 p-4">
                      <div className="flex flex-col items-center gap-2 text-slate-400">
                        <FileText size={32} />
                        <span className="text-xs font-medium truncate max-w-full px-2">{att.name || 'PDF Document'}</span>
                      </div>
                    </div>
                  ) : (
                    <img 
                      src={att.data} 
                      alt={`Attachment ${idx + 1}`} 
                      className="h-auto max-h-60 w-full object-cover" 
                    />
                  )}
                </div>
              ))}
            </div>
          )}

          <div className={`flex flex-col shadow-md rounded-2xl p-5 ${
            isUser 
              ? 'bg-indigo-600 text-white rounded-tr-sm' 
              : isError
                ? 'bg-red-900/20 text-red-200 border border-red-800 rounded-tl-sm'
                : 'bg-slate-800 text-slate-200 border border-slate-700 rounded-tl-sm'
          }`}>
            <div className="prose prose-invert prose-sm max-w-none break-words whitespace-pre-wrap leading-relaxed">
              {displayText}
            </div>

            {/* YouTube Recommendation Chip */}
            {videoTerm && (
              <div className="mt-4 pt-4 border-t border-slate-700/50 flex flex-wrap gap-2">
                <a 
                  href={`https://www.youtube.com/results?search_query=${encodeURIComponent(videoTerm)}`}
                  target="_blank"
                  rel="noopener noreferrer"
                  className="inline-flex items-center gap-2 bg-red-600/10 hover:bg-red-600/20 text-red-400 hover:text-red-300 px-3 py-2 rounded-lg text-xs font-medium transition-colors border border-red-600/20"
                >
                  <Youtube size={16} />
                  Watch: {videoTerm}
                  <ExternalLink size={12} className="ml-1 opacity-50" />
                </a>
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useRef, useState } from 'react';
import { Upload, FileText, Image as ImageIcon, Loader2, Plus, X } from 'lucide-react';
import { Attachment } from '../types';

interface ImageUploaderProps {
  onFilesSelected: (attachments: Attachment[]) => void;
  isLoading: boolean;
}

export const ImageUploader: React.FC<ImageUploaderProps> = ({ onFilesSelected, isLoading }) => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [dragActive, setDragActive] = useState(false);
  const [previews, setPreviews] = useState<Attachment[]>([]);

  const processFiles = (files: FileList | File[]) => {
    const newAttachments: Attachment[] = [];
    let processedCount = 0;
    const totalFiles = files.length;

    Array.from(files).forEach(file => {
      // Support images and PDFs
      if (file.type.startsWith('image/') || file.type === 'application/pdf') {
        const reader = new FileReader();
        reader.onloadend = () => {
          newAttachments.push({
            mimeType: file.type,
            data: reader.result as string,
            name: file.name
          });
          processedCount++;
          if (processedCount === totalFiles) {
            setPreviews(prev => [...prev, ...newAttachments]);
          }
        };
        reader.readAsDataURL(file);
      } else {
        processedCount++;
      }
    });
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files) processFiles(e.target.files);
  };

  const handleDrag = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    if (e.type === "dragenter" || e.type === "dragover") {
      setDragActive(true);
    } else if (e.type === "dragleave") {
      setDragActive(false);
    }
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setDragActive(false);
    if (e.dataTransfer.files) processFiles(e.dataTransfer.files);
  };

  const removeAttachment = (index: number) => {
    setPreviews(prev => prev.filter((_, i) => i !== index));
  };

  const handleSubmit = () => {
    if (previews.length > 0) {
      onFilesSelected(previews);
      setPreviews([]);
    }
  };

  return (
    <div className="w-full max-w-xl mx-auto mt-6 p-4">
      {/* Upload Area */}
      {previews.length === 0 ? (
        <div 
          className={`relative group border-2 border-dashed rounded-3xl p-10 text-center transition-all duration-300 ease-in-out cursor-pointer bg-slate-800
            ${dragActive ? 'border-indigo-500 bg-slate-800/80 scale-[1.01]' : 'border-slate-700 hover:border-indigo-500/50 hover:bg-slate-800/80'}
          `}
          onDragEnter={handleDrag}
          onDragLeave={handleDrag}
          onDragOver={handleDrag}
          onDrop={handleDrop}
          onClick={() => !isLoading && fileInputRef.current?.click()}
        >
          <input 
            ref={fileInputRef}
            type="file" 
            accept="image/*,application/pdf" 
            multiple
            className="hidden" 
            onChange={handleChange}
            disabled={isLoading}
          />

          <div className="flex flex-col items-center gap-4">
            <div className="w-16 h-16 rounded-full bg-slate-900 border border-slate-700 flex items-center justify-center text-indigo-400 group-hover:scale-110 group-hover:border-indigo-500/50 transition-all duration-300 shadow-xl">
              {isLoading ? <Loader2 className="animate-spin w-8 h-8" /> : <Upload className="w-8 h-8" />}
            </div>

            <div className="space-y-1">
              <h3 className="text-xl font-bold text-white">
                {isLoading ? 'Processing...' : 'Upload Materials'}
              </h3>
              <p className="text-slate-400 max-w-xs mx-auto text-sm">
                Drop problem images or PDF notes here.
              </p>
            </div>

            <div className="flex gap-3 mt-4">
               <span className="flex items-center gap-1.5 px-3 py-1.5 bg-slate-900 border border-slate-700 rounded-full text-xs font-medium text-slate-400">
                  <ImageIcon size={14} /> Images
               </span>
               <span className="flex items-center gap-1.5 px-3 py-1.5 bg-slate-900 border border-slate-700 rounded-full text-xs font-medium text-slate-400">
                  <FileText size={14} /> PDFs
               </span>
            </div>
          </div>
        </div>
      ) : (
        /* Preview Area */
        <div className="bg-slate-800 border border-slate-700 rounded-3xl p-6">
          <div className="mb-4 flex items-center justify-between">
            <h3 className="text-white font-semibold">Selected Files ({previews.length})</h3>
            <button 
              onClick={() => fileInputRef.current?.click()}
              className="text-xs flex items-center gap-1 text-indigo-400 hover:text-indigo-300"
            >
              <Plus size={14} /> Add more
            </button>
            <input 
              ref={fileInputRef}
              type="file" 
              accept="image/*,application/pdf" 
              multiple
              className="hidden" 
              onChange={handleChange}
            />
          </div>

          <div className="grid grid-cols-2 md:grid-cols-3 gap-3 mb-6 max-h-60 overflow-y-auto custom-scrollbar">
            {previews.map((file, idx) => (
              <div key={idx} className="relative group rounded-xl overflow-hidden bg-slate-900 border border-slate-700 aspect-square flex items-center justify-center">
                {file.mimeType === 'application/pdf' ? (
                  <div className="text-center p-2">
                    <FileText className="w-8 h-8 text-slate-500 mx-auto mb-1" />
                    <p className="text-[10px] text-slate-400 truncate w-full">{file.name}</p>
                  </div>
                ) : (
                  <img src={file.data} className="w-full h-full object-cover opacity-80" alt="preview" />
                )}
                <button 
                  onClick={(e) => { e.stopPropagation(); removeAttachment(idx); }}
                  className="absolute top-1 right-1 p-1 bg-red-500/80 hover:bg-red-600 text-white rounded-full opacity-0 group-hover:opacity-100 transition-opacity"
                >
                  <X size={12} />
                </button>
              </div>
            ))}
          </div>

          <button
            onClick={handleSubmit}
            disabled={isLoading}
            className="w-full py-3 bg-indigo-600 hover:bg-indigo-700 text-white rounded-xl font-medium transition-colors flex items-center justify-center gap-2"
          >
            {isLoading ? <Loader2 className="animate-spin w-4 h-4" /> : 'Start Analysis'}
          </button>
        </div>
      )}

      <p className="text-center mt-6 text-slate-500 text-xs">
        Powered by Gemini 3 Pro
      </p>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { Header } from './components/Header';
import { ImageUploader } from './components/ImageUploader';
import { ChatBubble } from './components/ChatBubble';
import { sendMessageToGemini } from './services/geminiService';
import { Message, Attachment } from './types';
import { Send, PlusCircle, EyeOff, Loader2 } from 'lucide-react';

const App: React.FC = () => {
  const [messages, setMessages] = useState<Message[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [inputText, setInputText] = useState('');
  // State for toggling the hidden "Reveal Answer" button
  const [showRevealOption, setShowRevealOption] = useState(false);

  const messagesEndRef = useRef<HTMLDivElement>(null);

  // Auto-scroll
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, isLoading]);

  const handleFilesSelected = async (attachments: Attachment[]) => {
    // 1. Add User Message with attachments
    const userMsg: Message = {
      id: Date.now().toString(),
      role: 'user',
      text: attachments.length > 1 ? 'Here are my materials. Can you help?' : 'Can you help me with this?',
      attachments: attachments
    };

    setMessages(prev => [...prev, userMsg]);
    setIsLoading(true);

    try {
      // 2. Call API (New Session)
      const responseText = await sendMessageToGemini([], { 
        attachments: attachments, 
        text: 'Analyze these materials. If there are notes, use them to guide me on the problem image.' 
      });

      // 3. Add Model Response
      const modelMsg: Message = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: responseText
      };
      setMessages(prev => [...prev, modelMsg]);
    } catch (error) {
      console.error(error);
      const errorMsg: Message = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: "I'm having trouble connecting to my brain right now. Please try again.",
        isError: true
      };
      setMessages(prev => [...prev, errorMsg]);
    } finally {
      setIsLoading(false);
    }
  };

  const handleSendText = async (overrideText?: string) => {
    const textToSend = overrideText || inputText;
    if (!textToSend.trim()) return;

    if (!overrideText) setInputText(''); 

    // 1. Add User Text Message
    const userMsg: Message = {
      id: Date.now().toString(),
      role: 'user',
      text: textToSend
    };
    setMessages(prev => [...prev, userMsg]);
    setIsLoading(true);

    try {
      // 2. Call API with history
      const responseText = await sendMessageToGemini(messages, { text: textToSend });

      // 3. Add Model Response
      const modelMsg: Message = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: responseText
      };
      setMessages(prev => [...prev, modelMsg]);
    } catch (error) {
       const errorMsg: Message = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: "Something went wrong. Please try asking again.",
        isError: true
      };
      setMessages(prev => [...prev, errorMsg]);
    } finally {
      setIsLoading(false);
    }
  };

  const handleRevealAnswer = () => {
    if (window.confirm("Are you sure you want to reveal the answer? Try to solve it first!")) {
      handleSendText("REVEAL_ANSWER");
      setShowRevealOption(false);
    }
  };

  const handleNewProblem = () => {
    // Just reset messages to show uploader again
    setMessages([]);
    setInputText('');
    setShowRevealOption(false);
  };

  return (
    <div className="flex flex-col h-full bg-slate-900">
      <Header />

      {/* Main Content Area */}
      <main className="flex-1 overflow-y-auto w-full max-w-4xl mx-auto p-4 md:p-6 scrollbar-hide">

        {messages.length === 0 ? (
          /* Empty State - Show Uploader */
          <div className="h-full flex flex-col justify-center items-center">
            <div className="text-center mb-8">
              <h2 className="text-3xl font-bold text-white mb-3">Stuck on a problem?</h2>
              <p className="text-slate-400 text-lg max-w-md mx-auto">
                Upload your problem image and any PDF notes. We'll solve it efficiently.
              </p>
            </div>
            <ImageUploader onFilesSelected={handleFilesSelected} isLoading={isLoading} />
          </div>
        ) : (
          /* Chat State */
          <div className="flex flex-col pb-32">
            {messages.map((msg) => (
              <ChatBubble key={msg.id} message={msg} />
            ))}

            {isLoading && (
              <div className="flex items-center gap-2 text-indigo-400 text-sm ml-2 animate-pulse mt-2">
                 <Loader2 className="w-4 h-4 animate-spin" /> Analyzing...
              </div>
            )}
            <div ref={messagesEndRef} />
          </div>
        )}

      </main>

      {/* Input Area (Only visible if chat is active) */}
      {messages.length > 0 && (
        <div className="sticky bottom-0 bg-slate-900/95 backdrop-blur-md border-t border-slate-800 p-4 pb-6 z-20">
          <div className="max-w-4xl mx-auto space-y-3">

            {/* Action Bar (Reveal / New Problem) */}
            <div className="flex justify-between items-center px-1">
               <button 
                  onClick={handleNewProblem}
                  className="flex items-center gap-2 text-xs font-medium text-slate-400 hover:text-white transition-colors py-1 px-2 rounded hover:bg-slate-800"
               >
                 <PlusCircle size={14} /> New Problem
               </button>

               <div className="flex items-center gap-2">
                  {!showRevealOption ? (
                    <button 
                      onClick={() => setShowRevealOption(true)}
                      className="text-xs text-slate-500 hover:text-slate-300 transition-colors"
                    >
                      I give up?
                    </button>
                  ) : (
                    <button 
                      onClick={handleRevealAnswer}
                      className="flex items-center gap-1.5 bg-slate-800 hover:bg-slate-700 text-slate-300 hover:text-white px-3 py-1.5 rounded-full text-xs font-medium transition-all border border-slate-700"
                    >
                      <EyeOff size={12} /> Reveal Answer
                    </button>
                  )}
               </div>
            </div>

            {/* Main Input */}
            <div className="relative">
              <textarea
                value={inputText}
                onChange={(e) => setInputText(e.target.value)}
                onKeyDown={(e) => {
                  if (e.key === 'Enter' && !e.shiftKey) {
                    e.preventDefault();
                    handleSendText();
                  }
                }}
                placeholder="Type your answer or question here..."
                className="w-full resize-none bg-slate-800 border border-slate-700 rounded-2xl px-5 py-4 pr-14 text-white placeholder-slate-500 focus:ring-2 focus:ring-indigo-500 focus:border-transparent transition-all max-h-32 min-h-[60px] shadow-sm"
                rows={1}
                disabled={isLoading}
              />
              <button
                onClick={() => handleSendText()}
                disabled={!inputText.trim() || isLoading}
                className="absolute right-3 bottom-3 p-2 bg-indigo-600 text-white rounded-xl hover:bg-indigo-500 disabled:opacity-50 disabled:bg-slate-700 disabled:cursor-not-allowed transition-all shadow-md"
              >
                <Send size={18} />
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

