import { GoogleGenAI, GenerateContentResponse } from "@google/genai";
import { Message, Attachment } from "../types";

// Initialize the client
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const SOCRATIC_SYSTEM_INSTRUCTION = `
You are SocraticSight, a patient, encouraging, and wise Socratic Tutor for students. 
Your goal is to help students learn math and physics by thinking critically.

**Context:**
The user may upload images of problems and PDF notes/reference materials. Use the notes to inform your guidance.

**Modes:**
1. **Normal Mode (Socratic Method):**
    - **Identify the Concept**: Briefly mention the underlying concept.
    - **Check the Work**: If the user uploaded work, check it for errors gently.
    - **Ask a Guiding Question**: Ask ONE clear question to help the user take the next step. DO NOT solve it yet.
    - **YouTube Suggestion**: At the end, output \`VIDEO_SEARCH: <concept search term>\`.

2. **Reveal Answer Mode:**
    - Triggered if the user says "REVEAL_ANSWER", "I give up", or asks for the solution directly.
    - **Step-by-Step Solution**: Provide the full, detailed derivation.
    - **Final Answer Block**: You MUST output the final answer in a distinct block at the end, like:

      **Final Answer:**
      $$ <answer> $$
      (or simply the value if Latex is not needed).

    - **Explanation**: Explain why this is the answer.
    - Still provide the \`VIDEO_SEARCH: <term>\` at the end.

**Formatting Rules**:
- Keep responses concise and friendly.
- Use Markdown.
- Ensure the \`VIDEO_SEARCH: ...\` tag is the last line.
`;

/**
 * Sends the chat history + new input to Gemini 3 Pro.
 */
export const sendMessageToGemini = async (
  history: Message[],
  newItem: { text?: string; attachments?: Attachment[] }
): Promise<string> => {
  try {
    const model = "gemini-3-pro-preview";

    // Format history
    const contents = history.map((msg) => {
      const parts: any[] = [];

      if (msg.attachments) {
        msg.attachments.forEach(att => {
          // Remove prefix if present, though usually handled before storage
          const base64Data = att.data.includes(',') ? att.data.split(',')[1] : att.data;
          parts.push({
            inlineData: {
              mimeType: att.mimeType,
              data: base64Data,
            },
          });
        });
      }

      if (msg.text) {
        parts.push({ text: msg.text });
      }

      return {
        role: msg.role === 'user' ? 'user' : 'model',
        parts: parts,
      };
    });

    // Add new item
    const newParts: any[] = [];
    if (newItem.attachments) {
        newItem.attachments.forEach(att => {
            const base64Data = att.data.includes(',') ? att.data.split(',')[1] : att.data;
            newParts.push({
                inlineData: {
                    mimeType: att.mimeType,
                    data: base64Data
                }
            });
        });
    }
    if (newItem.text) {
        newParts.push({ text: newItem.text });
    }

    contents.push({
        role: 'user',
        parts: newParts
    });

    const response: GenerateContentResponse = await ai.models.generateContent({
      model: model,
      contents: contents,
      config: {
        systemInstruction: SOCRATIC_SYSTEM_INSTRUCTION,
        thinkingConfig: { thinkingBudget: 1024 },
      },
    });

    if (response.text) {
      return response.text;
    } else {
      throw new Error("No response text received from Gemini.");
    }
  } catch (error) {
    console.error("Gemini Service Error:", error);
    throw error;
  }
};

/**
 * Generates a solved version of the provided image.
 */
export const generateSolvedImage = async (base64Image: string): Promise<string> => {
  try {
    // Clean base64 string
    const cleanBase64 = base64Image.includes(',') ? base64Image.split(',')[1] : base64Image;

    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [
          { 
            inlineData: { 
              mimeType: 'image/jpeg', // Assuming jpeg/png generic compatibility
              data: cleanBase64 
            } 
          },
          { 
            text: "Solve the math or physics problem shown in the image. Output a NEW image that is identical to the original, but with the full solution steps and final answer written in the blank space or next to the problem. Use a handwriting style that closely matches the original text in the image." 
          },
        ],
      },
      // Config not needed for simple image edit/generation unless specific aspect ratio desired, 
      // but here we want to preserve context so we let the model decide.
    });

    // Extract image from response
    if (response.candidates && response.candidates[0].content.parts) {
      for (const part of response.candidates[0].content.parts) {
        if (part.inlineData && part.inlineData.data) {
           return part.inlineData.data;
        }
      }
    }

    throw new Error("No image generated.");
  } catch (error) {
    console.error("Image Generation Error:", error);
    throw error;
  }
};

import React, { useState } from 'react';
import { Session, Project } from '../types';
import { MessageSquare, Plus, Trash2, X, Clock, Folder, FolderOpen, Pencil, Check } from 'lucide-react';

interface SidebarProps {
  sessions: Session[];
  projects: Project[];
  currentSessionId: string | null;
  onSelectSession: (id: string) => void;
  onNewChat: () => void;
  onDeleteSession: (id: string, e: React.MouseEvent) => void;
  onRenameSession: (id: string, newTitle: string) => void;
  onCreateProject: (name: string) => void;
  onMoveSession: (sessionId: string, projectId?: string) => void;
  onDeleteProject: (projectId: string) => void;
  isOpen: boolean;
  onClose: () => void;
}

export const Sidebar: React.FC<SidebarProps> = ({
  sessions,
  projects,
  currentSessionId,
  onSelectSession,
  onNewChat,
  onDeleteSession,
  onRenameSession,
  onCreateProject,
  onMoveSession,
  onDeleteProject,
  isOpen,
  onClose
}) => {
  const [editingSessionId, setEditingSessionId] = useState<string | null>(null);
  const [editTitle, setEditTitle] = useState('');
  const [newProjectName, setNewProjectName] = useState('');
  const [isCreatingProject, setIsCreatingProject] = useState(false);
  const [expandedProjects, setExpandedProjects] = useState<Set<string>>(new Set(projects.map(p => p.id)));

  const toggleProject = (projectId: string) => {
    const newSet = new Set(expandedProjects);
    if (newSet.has(projectId)) {
      newSet.delete(projectId);
    } else {
      newSet.add(projectId);
    }
    setExpandedProjects(newSet);
  };

  const startEditing = (session: Session, e: React.MouseEvent) => {
    e.stopPropagation();
    setEditingSessionId(session.id);
    setEditTitle(session.title);
  };

  const saveTitle = (sessionId: string) => {
    if (editTitle.trim()) {
      onRenameSession(sessionId, editTitle);
    }
    setEditingSessionId(null);
  };

  const handleCreateProject = () => {
    if (newProjectName.trim()) {
      onCreateProject(newProjectName);
      setNewProjectName('');
      setIsCreatingProject(false);
    }
  };

  // Drag and Drop Handlers
  const onDragStart = (e: React.DragEvent, sessionId: string) => {
    e.dataTransfer.setData("sessionId", sessionId);
  };

  const onDragOver = (e: React.DragEvent) => {
    e.preventDefault();
  };

  const onDrop = (e: React.DragEvent, projectId?: string) => {
    e.preventDefault();
    const sessionId = e.dataTransfer.getData("sessionId");
    if (sessionId) {
      onMoveSession(sessionId, projectId);
    }
  };

  const renderSessionItem = (session: Session) => (
    <div
      key={session.id}
      draggable
      onDragStart={(e) => onDragStart(e, session.id)}
      onClick={() => {
        onSelectSession(session.id);
        if (window.innerWidth < 768) onClose();
      }}
      className={`
        group flex items-center gap-3 p-3 rounded-lg cursor-pointer transition-all border
        ${currentSessionId === session.id 
          ? 'bg-slate-800 border-slate-700 text-white shadow-sm' 
          : 'text-slate-400 border-transparent hover:bg-slate-900 hover:text-slate-200'
        }
      `}
    >
      <MessageSquare size={18} className={currentSessionId === session.id ? 'text-indigo-400' : 'text-slate-600'} />

      <div className="flex-1 overflow-hidden">
        {editingSessionId === session.id ? (
          <div className="flex items-center gap-1" onClick={e => e.stopPropagation()}>
            <input
              type="text"
              value={editTitle}
              onChange={(e) => setEditTitle(e.target.value)}
              className="w-full bg-slate-950 text-white text-xs p-1 rounded border border-indigo-500 focus:outline-none"
              autoFocus
              onKeyDown={(e) => {
                if (e.key === 'Enter') saveTitle(session.id);
                if (e.key === 'Escape') setEditingSessionId(null);
              }}
            />
            <button onClick={() => saveTitle(session.id)} className="text-green-400 hover:text-green-300">
              <Check size={14} />
            </button>
          </div>
        ) : (
          <div className="flex flex-col">
            <h3 className="text-sm font-medium truncate group-hover:text-slate-200">{session.title}</h3>
            <p className="text-[10px] text-slate-500 truncate">
              {new Date(session.timestamp).toLocaleDateString()}
            </p>
          </div>
        )}
      </div>

      {!editingSessionId && (
        <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
          <button
            onClick={(e) => startEditing(session, e)}
            className="p-1.5 text-slate-500 hover:text-indigo-400 hover:bg-indigo-900/20 rounded-md"
            title="Rename"
          >
            <Pencil size={12} />
          </button>
          <button
            onClick={(e) => onDeleteSession(session.id, e)}
            className="p-1.5 text-slate-500 hover:text-red-400 hover:bg-red-900/20 rounded-md"
            title="Delete"
          >
            <Trash2 size={12} />
          </button>
        </div>
      )}
    </div>
  );

  return (
    <>
      {/* Mobile Overlay */}
      {isOpen && (
        <div 
          className="fixed inset-0 bg-black/50 z-30 md:hidden backdrop-blur-sm"
          onClick={onClose}
        />
      )}

      {/* Sidebar Container */}
      <div className={`
        fixed top-0 left-0 bottom-0 w-72 bg-slate-950 border-r border-slate-800 z-40 transform transition-transform duration-300 ease-in-out flex flex-col
        ${isOpen ? 'translate-x-0' : '-translate-x-full'}
        md:relative md:translate-x-0
      `}>

        {/* Header */}
        <div className="p-4 border-b border-slate-800 flex items-center justify-between">
          <h2 className="text-white font-bold text-lg tracking-tight">Library</h2>
          <button onClick={onClose} className="md:hidden text-slate-400 hover:text-white">
            <X size={20} />
          </button>
        </div>

        {/* Actions */}
        <div className="p-4 space-y-2">
          <button
            onClick={() => {
              onNewChat();
              if (window.innerWidth < 768) onClose();
            }}
            className="w-full flex items-center justify-center gap-2 bg-indigo-600 hover:bg-indigo-700 text-white py-3 rounded-xl transition-colors font-medium shadow-lg shadow-indigo-900/20"
          >
            <Plus size={18} />
            New Problem
          </button>

          {!isCreatingProject ? (
            <button
              onClick={() => setIsCreatingProject(true)}
              className="w-full flex items-center justify-center gap-2 bg-slate-800 hover:bg-slate-700 text-slate-300 py-2 rounded-xl transition-colors text-xs font-medium border border-slate-700"
            >
              <Folder size={14} /> Create Project
            </button>
          ) : (
            <div className="flex gap-2 animate-in fade-in slide-in-from-top-1">
              <input
                autoFocus
                type="text"
                placeholder="Project Name"
                className="flex-1 bg-slate-900 border border-slate-700 rounded-lg px-2 text-xs text-white focus:border-indigo-500 focus:outline-none"
                value={newProjectName}
                onChange={(e) => setNewProjectName(e.target.value)}
                onKeyDown={(e) => {
                  if (e.key === 'Enter') handleCreateProject();
                  if (e.key === 'Escape') setIsCreatingProject(false);
                }}
              />
              <button 
                onClick={handleCreateProject}
                className="p-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-500"
              >
                <Check size={14} />
              </button>
              <button 
                onClick={() => setIsCreatingProject(false)}
                className="p-2 bg-slate-700 text-slate-300 rounded-lg hover:bg-slate-600"
              >
                <X size={14} />
              </button>
            </div>
          )}
        </div>

        {/* Session List */}
        <div className="flex-1 overflow-y-auto px-2 custom-scrollbar space-y-1 pb-4">

          {/* Projects */}
          {projects.map(project => {
            const projectSessions = sessions.filter(s => s.projectId === project.id);
            const isExpanded = expandedProjects.has(project.id);

            return (
              <div 
                key={project.id} 
                className="mb-1"
                onDragOver={onDragOver}
                onDrop={(e) => onDrop(e, project.id)}
              >
                <div 
                  className="group flex items-center justify-between px-3 py-2 text-slate-400 hover:text-white cursor-pointer hover:bg-slate-900 rounded-lg"
                  onClick={() => toggleProject(project.id)}
                >
                  <div className="flex items-center gap-2">
                    {isExpanded ? <FolderOpen size={16} className="text-amber-500/80" /> : <Folder size={16} className="text-slate-600 group-hover:text-amber-500/80 transition-colors" />}
                    <span className="text-sm font-medium">{project.name}</span>
                    <span className="text-[10px] bg-slate-800 px-1.5 py-0.5 rounded-full text-slate-500 group-hover:text-slate-400">
                      {projectSessions.length}
                    </span>
                  </div>
                  <button 
                    onClick={(e) => { e.stopPropagation(); onDeleteProject(project.id); }}
                    className="opacity-0 group-hover:opacity-100 p-1 hover:text-red-400 hover:bg-red-900/20 rounded"
                  >
                    <Trash2 size={12} />
                  </button>
                </div>

                {isExpanded && (
                  <div className="ml-2 pl-2 border-l border-slate-800 space-y-1 mt-1">
                    {projectSessions.length === 0 ? (
                      <div className="text-[10px] text-slate-600 py-2 px-2 italic">Drag chats here</div>
                    ) : (
                      projectSessions.map(renderSessionItem)
                    )}
                  </div>
                )}
              </div>
            );
          })}

          {/* Uncategorized Header (Implicit) */}
          <div 
            className="mt-4 mb-2 px-3 text-xs font-semibold text-slate-500 uppercase tracking-wider"
             onDragOver={onDragOver}
             onDrop={(e) => onDrop(e, undefined)} // Undefined projectId means uncategorized
          >
            Uncategorized
          </div>

          <div 
            className="space-y-1 min-h-[50px]"
            onDragOver={onDragOver}
            onDrop={(e) => onDrop(e, undefined)}
          >
            {sessions.filter(s => !s.projectId).length === 0 ? (
              <div className="flex flex-col items-center justify-center h-20 text-slate-700">
                <p className="text-xs">No active chats</p>
              </div>
            ) : (
              sessions.filter(s => !s.projectId).map(renderSessionItem)
            )}
          </div>

        </div>
      </div>
    </>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { Header } from './components/Header';
import { ImageUploader } from './components/ImageUploader';
import { ChatBubble } from './components/ChatBubble';
import { Sidebar } from './components/Sidebar';
import { sendMessageToGemini, generateSolvedImage } from './services/geminiService';
import { Message, Attachment, Session, Project } from './types';
import { Send, EyeOff, Loader2, Sparkles } from 'lucide-react';

const STORAGE_KEY_SESSIONS = 'socratic_sessions_v1';
const STORAGE_KEY_PROJECTS = 'socratic_projects_v1';

const App: React.FC = () => {
  const [sessions, setSessions] = useState<Session[]>([]);
  const [projects, setProjects] = useState<Project[]>([]);
  const [currentSessionId, setCurrentSessionId] = useState<string | null>(null);
  const [messages, setMessages] = useState<Message[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [inputText, setInputText] = useState('');
  const [showRevealOption, setShowRevealOption] = useState(false);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);

  const messagesEndRef = useRef<HTMLDivElement>(null);

  // Load data
  useEffect(() => {
    try {
      const savedSessions = localStorage.getItem(STORAGE_KEY_SESSIONS);
      const savedProjects = localStorage.getItem(STORAGE_KEY_PROJECTS);
      if (savedSessions) setSessions(JSON.parse(savedSessions));
      if (savedProjects) setProjects(JSON.parse(savedProjects));
    } catch (e) {
      console.error("Failed to load data", e);
    }
  }, []);

  // Save data
  useEffect(() => {
    try {
      localStorage.setItem(STORAGE_KEY_SESSIONS, JSON.stringify(sessions));
      localStorage.setItem(STORAGE_KEY_PROJECTS, JSON.stringify(projects));
    } catch (e) {
      console.error("Storage quota exceeded", e);
    }
  }, [sessions, projects]);

  // Sync messages
  useEffect(() => {
    if (currentSessionId) {
      setSessions(prev => prev.map(s => 
        s.id === currentSessionId 
          ? { ...s, messages: messages, title: generateTitle(messages, s.title) } 
          : s
      ));
    }
  }, [messages, currentSessionId]);

  // Auto-scroll
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, isLoading]);

  const generateTitle = (msgs: Message[], currentTitle: string) => {
    // Only generate title if it's default
    if ((currentTitle === 'New Session' || currentTitle === 'New Problem') && msgs.length > 0) {
       const firstUserMsg = msgs.find(m => m.role === 'user');
       if (firstUserMsg) {
         if (firstUserMsg.attachments && firstUserMsg.attachments.length > 0) {
            return `Problem ${new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}`;
         }
         return firstUserMsg.text.slice(0, 30) + (firstUserMsg.text.length > 30 ? '...' : '');
       }
    }
    return currentTitle;
  };

  // --- Session Management ---

  const createNewSession = () => {
    const newSession: Session = {
      id: Date.now().toString(),
      title: 'New Problem',
      timestamp: Date.now(),
      messages: []
    };
    setSessions(prev => [newSession, ...prev]);
    setCurrentSessionId(newSession.id);
    setMessages([]);
    setShowRevealOption(false);
    setIsSidebarOpen(false);
  };

  const handleSelectSession = (id: string) => {
    const session = sessions.find(s => s.id === id);
    if (session) {
      setCurrentSessionId(session.id);
      setMessages(session.messages);
      setShowRevealOption(false);
      setIsSidebarOpen(false);
    }
  };

  const handleDeleteSession = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    if (window.confirm("Delete this chat?")) {
      setSessions(prev => prev.filter(s => s.id !== id));
      if (currentSessionId === id) {
        setCurrentSessionId(null);
        setMessages([]);
      }
    }
  };

  const handleRenameSession = (id: string, newTitle: string) => {
    setSessions(prev => prev.map(s => s.id === id ? { ...s, title: newTitle } : s));
  };

  const handleMoveSession = (sessionId: string, projectId?: string) => {
    setSessions(prev => prev.map(s => s.id === sessionId ? { ...s, projectId } : s));
  };

  // --- Project Management ---

  const handleCreateProject = (name: string) => {
    const newProject: Project = {
      id: Date.now().toString(),
      name
    };
    setProjects(prev => [...prev, newProject]);
  };

  const handleDeleteProject = (projectId: string) => {
    if (window.confirm("Delete this project? Chats will be moved to Uncategorized.")) {
      setProjects(prev => prev.filter(p => p.id !== projectId));
      // Move sessions to uncategorized
      setSessions(prev => prev.map(s => s.projectId === projectId ? { ...s, projectId: undefined } : s));
    }
  };

  // --- Chat & Logic ---

  const handleFilesSelected = async (attachments: Attachment[]) => {
    if (!currentSessionId) {
       const newSession: Session = {
        id: Date.now().toString(),
        title: 'New Problem',
        timestamp: Date.now(),
        messages: []
      };
      setSessions(prev => [newSession, ...prev]);
      setCurrentSessionId(newSession.id);
    }

    const userMsg: Message = {
      id: Date.now().toString(),
      role: 'user',
      text: attachments.length > 1 ? 'Here are my materials.' : 'Can you help me with this?',
      attachments: attachments
    };

    setMessages(prev => [...prev, userMsg]);
    setIsLoading(true);

    try {
      const responseText = await sendMessageToGemini(messages, { 
        attachments: attachments, 
        text: 'Analyze these materials. If there are notes, use them to guide me on the problem image.' 
      });

      const modelMsg: Message = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: responseText
      };
      setMessages(prev => [...prev, userMsg, modelMsg]); 
    } catch (error) {
      console.error(error);
      const errorMsg: Message = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: "I'm having trouble connecting to my brain right now. Please try again.",
        isError: true
      };
      setMessages(prev => [...prev, userMsg, errorMsg]);
    } finally {
      setIsLoading(false);
    }
  };

  const handleSendText = async (overrideText?: string) => {
    const textToSend = overrideText || inputText;
    if (!textToSend.trim()) return;

    if (!overrideText) setInputText(''); 

    const userMsg: Message = {
      id: Date.now().toString(),
      role: 'user',
      text: textToSend
    };

    const newMessages = [...messages, userMsg];
    setMessages(newMessages);
    setIsLoading(true);

    try {
      const responseText = await sendMessageToGemini(messages, { text: textToSend });
      const modelMsg: Message = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: responseText
      };
      setMessages([...newMessages, modelMsg]);
    } catch (error) {
       const errorMsg: Message = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: "Something went wrong. Please try asking again.",
        isError: true
      };
      setMessages([...newMessages, errorMsg]);
    } finally {
      setIsLoading(false);
    }
  };

  // --- Image Generation Logic for Reveal Answer ---

  const handleFillInAnswer = async () => {
    if (!window.confirm("I will solve the problem and write the answer directly on your image. Ready?")) return;

    setIsLoading(true);
    setShowRevealOption(false);

    try {
      // 1. Find the most recent user image in history
      const lastImageMsg = [...messages].reverse().find(m => m.role === 'user' && m.attachments?.some(a => a.mimeType.startsWith('image/')));

      if (!lastImageMsg || !lastImageMsg.attachments) {
        throw new Error("No image found to solve.");
      }

      const targetImage = lastImageMsg.attachments.find(a => a.mimeType.startsWith('image/'));
      if (!targetImage) throw new Error("Image attachment missing.");

      // 2. Add user system message indicating the request
      const userRequestMsg: Message = {
        id: Date.now().toString(),
        role: 'user',
        text: "Generate the solution in my handwriting on the image."
      };
      setMessages(prev => [...prev, userRequestMsg]);

      // 3. Call Image Generation Service
      const generatedImageBase64 = await generateSolvedImage(targetImage.data);
      const generatedImageUrl = `data:image/jpeg;base64,${generatedImageBase64}`;

      // 4. Add Model Response with Image
      const modelResponseMsg: Message = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: "I've written the solution on the image for you:",
        attachments: [{
          mimeType: 'image/jpeg',
          data: generatedImageUrl,
          name: 'solved_problem.jpg'
        }]
      };

      setMessages(prev => [...prev, modelResponseMsg]);

    } catch (error) {
      console.error("Generation failed", error);
       const errorMsg: Message = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: "I couldn't generate the handwriting solution on the image. Please try the text-based reveal instead.",
        isError: true
      };
      setMessages(prev => [...prev, errorMsg]);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="flex h-full bg-slate-950 overflow-hidden">

      <Sidebar 
        sessions={sessions}
        projects={projects}
        currentSessionId={currentSessionId}
        onSelectSession={handleSelectSession}
        onNewChat={createNewSession}
        onDeleteSession={handleDeleteSession}
        onRenameSession={handleRenameSession}
        onCreateProject={handleCreateProject}
        onDeleteProject={handleDeleteProject}
        onMoveSession={handleMoveSession}
        isOpen={isSidebarOpen}
        onClose={() => setIsSidebarOpen(false)}
      />

      <div className="flex-1 flex flex-col h-full w-full bg-slate-900 relative">
        <Header onMenuClick={() => setIsSidebarOpen(true)} />

        {/* Main Content Area */}
        <main className="flex-1 overflow-y-auto w-full max-w-4xl mx-auto p-4 md:p-6 scrollbar-hide">

          {!currentSessionId || messages.length === 0 ? (
            /* Empty State - Show Uploader */
            <div className="h-full flex flex-col justify-center items-center">
              <div className="text-center mb-8 px-4">
                <h2 className="text-3xl font-bold text-white mb-3">SocraticSight</h2>
                <p className="text-slate-400 text-lg max-w-md mx-auto">
                  Upload problems or notes. I'll help you solve them step-by-step.
                </p>
              </div>
              <ImageUploader onFilesSelected={handleFilesSelected} isLoading={isLoading} />
            </div>
          ) : (
            /* Chat State */
            <div className="flex flex-col pb-32">
              {messages.map((msg) => (
                <ChatBubble key={msg.id} message={msg} />
              ))}

              {isLoading && (
                <div className="flex items-center gap-2 text-indigo-400 text-sm ml-2 animate-pulse mt-2">
                   <Loader2 className="w-4 h-4 animate-spin" /> Thinking...
                </div>
              )}
              <div ref={messagesEndRef} />
            </div>
          )}

        </main>

        {/* Input Area (Only visible if session active and has messages) */}
        {currentSessionId && messages.length > 0 && (
          <div className="sticky bottom-0 bg-slate-900/95 backdrop-blur-md border-t border-slate-800 p-4 pb-6 z-20">
            <div className="max-w-4xl mx-auto space-y-3">

              {/* Action Bar */}
              <div className="flex justify-end items-center px-1">
                 <div className="flex items-center gap-2">
                    {!showRevealOption ? (
                      <button 
                        onClick={() => setShowRevealOption(true)}
                        className="text-xs text-slate-500 hover:text-slate-300 transition-colors"
                      >
                        I give up?
                      </button>
                    ) : (
                      <div className="flex gap-2 animate-in slide-in-from-right-2 fade-in">
                         <button 
                          onClick={() => handleSendText("REVEAL_ANSWER")}
                          className="flex items-center gap-1.5 bg-slate-800 hover:bg-slate-700 text-slate-300 hover:text-white px-3 py-1.5 rounded-full text-xs font-medium transition-all border border-slate-700"
                        >
                          <EyeOff size={12} /> Text Answer
                        </button>
                        <button 
                          onClick={handleFillInAnswer}
                          className="flex items-center gap-1.5 bg-indigo-600 hover:bg-indigo-500 text-white px-3 py-1.5 rounded-full text-xs font-medium transition-all shadow-md shadow-indigo-900/30"
                        >
                          <Sparkles size={12} /> Fill in Answer
                        </button>
                      </div>
                    )}
                 </div>
              </div>

              {/* Main Input */}
              <div className="relative">
                <textarea
                  value={inputText}
                  onChange={(e) => setInputText(e.target.value)}
                  onKeyDown={(e) => {
                    if (e.key === 'Enter' && !e.shiftKey) {
                      e.preventDefault();
                      handleSendText();
                    }
                  }}
                  placeholder="Type your answer or question here..."
                  className="w-full resize-none bg-slate-800 border border-slate-700 rounded-2xl px-5 py-4 pr-14 text-white placeholder-slate-500 focus:ring-2 focus:ring-indigo-500 focus:border-transparent transition-all max-h-32 min-h-[60px] shadow-sm"
                  rows={1}
                  disabled={isLoading}
                />
                <button
                  onClick={() => handleSendText()}
                  disabled={!inputText.trim() || isLoading}
                  className="absolute right-3 bottom-3 p-2 bg-indigo-600 text-white rounded-xl hover:bg-indigo-500 disabled:opacity-50 disabled:bg-slate-700 disabled:cursor-not-allowed transition-all shadow-md"
                >
                  <Send size={18} />
                </button>
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

